import requests
from transformers import GPT2Tokenizer, GPT2Model

# Initialize the OpenAI API client
openai = requests.Session()
openai.headers['Authorization'] = 'Bearer YOUR_API_KEY'

# Define the GPT model and tokenizer
tokenizer = GPT2Tokenizer.from_pretrained('gpt2')
model = GPT2Model.from_pretrained('gpt2')

def chatbot(user_input):
    # Concatenate system instructions with user input
    text = 'Hi! I am your customer support assistant. How can I assist you today?' + user_input
    
    # Convert the text to a tensor
    encoding = tokenizer.encode(text, return_tensors='pt')
    
    # Pass the tensor through the GPT model
    response = openai.post('https://api.openai.com/v1/engines/davinci/completions', data={'prompt': text})
    
    # Convert the response to a string
    completion = tokenizer.decode(response.json()['choices'][0]['text'], skip_special_tokens=True)
    
    return completion